// PromptBuilder assembles prompts from AnswerContext within a token budget.
type PromptBuilder struct{}

// SelectChunks returns the subset of chunks that fit within tokenBudget.
func (pb *PromptBuilder) SelectChunks(ctx *AnswerContext, tokenBudget int) []*ScoredChunk {
	sortedChunks := make([]*ScoredChunk, len(ctx.Chunks))
	copy(sortedChunks, ctx.Chunks)
	sort.Slice(sortedChunks, func(i, j int) bool {
		ti, ok := tier[sortedChunks[i].Provenance]
		if !ok {
			ti = 4
		}
		tj, ok := tier[sortedChunks[j].Provenance]
		if !ok {
			tj = 4
		}
		return ti < tj
	})
	used := estimateTokens(pb.buildHeader(ctx))
	selected := make([]*ScoredChunk, 0)
	for _, sc := range sortedChunks {
		cost := estimateTokens(sc.Chunk.Content)
		if used+cost > tokenBudget {
			break
		}
		used += cost
		selected = append(selected, sc)
	}
	return selected
}

