// Build assembles the prompt string, respecting tokenBudget.
func (pb *PromptBuilder) Build(ctx *AnswerContext, tokenBudget int) string {
	selected := pb.SelectChunks(ctx, tokenBudget)
	parts := []string{pb.buildHeader(ctx)}
	for _, sc := range selected {
		parts = append(parts, fmt.Sprintf("[%s] %s:\n%s", sc.Provenance, sc.Chunk.DocumentName, sc.Chunk.Content))
	}
	return strings.Join(parts, "\n\n")
}

