// buildHeader assembles the header lines from context.
func (pb *PromptBuilder) buildHeader(ctx *AnswerContext) string {
	parts := make([]string, 0)
	if ctx.CommunityContext != nil && len(*ctx.CommunityContext) > 0 {
		parts = append(parts, fmt.Sprintf("Context: %s", *ctx.CommunityContext))
	}
	parts = append(parts, fmt.Sprintf("Query: %s", ctx.Query))
	return strings.Join(parts, "\n")
}

// AnswerContext holds retrieval output packaged for prompt assembly.
type AnswerContext struct {
	Chunks           []*ScoredChunk
	Query            string
	CommunityContext *string
	ActiveEntities   []string
}

// NewAnswerContext constructs an AnswerContext with required fields.
// communityContext may be nil; activeEntities may be nil (treated as empty).
func NewAnswerContext(chunks []*ScoredChunk, query string, communityContext *string, activeEntities []string) *AnswerContext {
	if activeEntities == nil {
		activeEntities = []string{}
	}
	return &AnswerContext{
		Chunks:           chunks,
		Query:            query,
		CommunityContext: communityContext,
		ActiveEntities:   activeEntities,
	}
}

