var tier = map[string]int{
	"seed":             0,
	"structural":       1,
	"entity_adjacent":  2,
	"cluster_adjacent": 3,
}

// estimateTokens approximates the token count for text.
func estimateTokens(text string) int {
	n := len(text) / 4
	if n < 1 {
		return 1
	}
	return n
}

